INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aas_durable_peace','A historic peace is ending a 30-year conflict and normalizing the region','Ein historischer Frieden beendet einen 30-jährigen Konflikt und normalisiert die Region','Western and Turkish framing celebrates the Armenia-Azerbaijan settlement -- and the parallel Armenia-Turkey opening -- as a historic, US-brokered peace that ends decades of war, delimits the border, reopens trade and railways, and integrates the South Caucasus.','Die westliche und türkische Deutung feiert die Regelung zwischen Armenien und Aserbaidschan -- samt der parallelen Öffnung zwischen Armenien und der Türkei -- als historischen, von den USA vermittelten Frieden, der jahrzehntelangen Krieg beendet, die Grenze zieht, Handel und Bahnverbindungen öffnet und den Südkaukasus integriert.',ARRAY['ASIA-CAUCASUS'],ARRAY['peace deal','peace treaty','historic','normalization','normalisation','breakthrough','ends conflict','reconciliation','regional integration','signed','direct trade','reopen','Friedensabkommen','historisch','Normalisierung','Aussöhnung','мирный договор','историческое','нормализация','примирение'],true,ARRAY['Reuters','Euronews','Euronews.com','Associated Press','BBC World','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','ANSA','La Repubblica','El País','Novinite','The National','Daily Sabah','Anadolu Agency','TRT World','Express Tribune','Dawn'],'armenia_azerbaijan_settlement',1,'Historic peace and normalization','Historischer Frieden und Normalisierung',2,true) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('aas_contested_settlement','The settlement is a contested, externally shaped arrangement rather than a genuine peace','Die Regelung ist ein umstrittenes, von außen geformtes Arrangement statt eines echten Friedens','Critics reject the triumphant peace account from two directions: a pro-Armenian and human-rights framing sees a capitulation imposed on a defeated Armenia that leaves the 2023 exodus, prisoners of war and war-crimes accountability unaddressed; a Russian framing sees a Western- and Turkish-brokered arrangement that sidelines Moscow and its peacekeepers.','Kritiker weisen die triumphale Friedenserzählung aus zwei Richtungen zurück: eine proarmenische und menschenrechtliche Deutung sieht eine einem besiegten Armenien aufgezwungene Kapitulation, die den Exodus von 2023, Kriegsgefangene und die Ahndung von Kriegsverbrechen ungeklärt lässt; eine russische Deutung sieht ein westlich-türkisch vermitteltes Arrangement, das Moskau und seine Friedenstruppen an den Rand drängt.',ARRAY['ASIA-CAUCASUS'],ARRAY['ethnic cleansing','forced displacement','exodus','capitulation','dictated','imposed','prisoners of war','prisoner','war crimes','torture','Folter','unpunished','betrayed','betrayal','betray','trial','convicted','verurteilt','sidelined','hijack','peacekeepers','excludes Russia','ethnische Säuberung','Vertreibung','Kriegsverbrechen','Kriegsgefangene','Kapitulation','aufgezwungen','an den Rand','этническая чистка','военнопленные','капитуляция','навязанный','в обход России'],true,ARRAY['France 24 (EN)','France 24','Le Figaro','Le Monde','The Guardian','Deutsche Welle','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Haaretz','Carnegie Endowment','TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian'],'armenia_azerbaijan_settlement',2,'Contested / imposed settlement','Umstrittene / aufgezwungene Regelung', -2,true) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('awp_european_choice','Armenia''s turn to Europe is a sovereign, democratic escape from Russian domination','Armeniens Hinwendung zu Europa ist ein souveräner, demokratischer Ausbruch aus russischer Vorherrschaft','Western/pro-European framing celebrates Armenia''s pivot as a hard-won, democratic choice: a sovereign state escaping a failed Russian security guarantee, winning elections against Moscow''s pressure, and charting a European future through EU trade, accession talks and the EPC summit.','Die westlich/proeuropäische Deutung feiert Armeniens Schwenk als hart erkämpfte demokratische Entscheidung: ein souveräner Staat, der einer gescheiterten russischen Sicherheitsgarantie entkommt, gegen Moskaus Druck Wahlen gewinnt und über EU-Handel, Beitrittsgespräche und den EPG-Gipfel eine europäische Zukunft ansteuert.',ARRAY['ASIA-CAUCASUS'],ARRAY['pivot to Europe','turn to Europe','away from Russia','break with Russia','sovereign choice','pro-Western','historic shift','escape Moscow','European future','defies Russia','Hinwendung nach Europa','Abkehr von Russland','souveräne Entscheidung','historischer Wandel','разворот на Запад','суверенный выбор','европейский выбор'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','Washington Post','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Tagesschau','ANSA','La Repubblica','El País','Le Figaro','Carnegie Endowment','Novinite','Kyiv Post','LRT English','The Economist','Sky News','ABC News','The Australian','The National'],'armenia_western_pivot',1,'Sovereign European choice','Souveräne europäische Entscheidung',2,true) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('awp_russian_capture','Armenia is being dragged into an anti-Russian orbit by a Western-engineered capture','Armenien wird durch eine vom Westen inszenierte Vereinnahmung in eine antirussische Umlaufbahn gezogen','Russian state framing treats the pivot as a hostile Western operation: elections tainted by "collective West" interference, Pashinyan a Western puppet betraying an ally, Armenia headed for a "Ukraine scenario" and economic ruin once it forfeits EAEU and CSTO benefits.','Die russische Staatsdeutung sieht den Schwenk als feindliche Westoperation: durch Einmischung des "kollektiven Westens" verfälschte Wahlen, Paschinjan als westliche Marionette und Bündnisverräter, Armenien auf dem Weg in ein "Ukraine-Szenario" und den wirtschaftlichen Ruin, sobald es die Vorteile von EAWU und OVKS verspielt.',ARRAY['ASIA-CAUCASUS'],ARRAY['collective West','interference','foreign interference','rigged','irregularities','puppet','Ukraine scenario','economic ruin','freeloading','betrayal','pressure on opposition','Einmischung','Marionette','manipuliert','вмешательство','коллективный Запад','майдан','русофоб'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian'],'armenia_western_pivot',3,'Western capture / betrayal of alliance','Westliche Vereinnahmung / Bündnisverrat', -2,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cpc_western_engagement','Outside engagement brings beneficial partnership and integration to the region','Äußeres Engagement bringt der Region nützliche Partnerschaft und Integration','A Western, Turkish and Israeli framing presents outside engagement in the South Caucasus as beneficial partnership and integration: Azerbaijani energy exports to Europe through SOCAR and the Southern Gas Corridor, Israeli and Turkish security and economic ties, a growing US role, and -- as an expression of Western and Israeli moral engagement -- recognition of the Armenian Genocide.','Eine westliche, türkische und israelische Deutung stellt das äußere Engagement im Südkaukasus als nützliche Partnerschaft und Integration dar: aserbaidschanische Energieexporte nach Europa über SOCAR und den Südlichen Gaskorridor, israelische und türkische Sicherheits- und Wirtschaftsbeziehungen, eine wachsende US-Rolle und -- als Ausdruck westlichen und israelischen moralischen Engagements -- die Anerkennung des Völkermords an den Armeniern.',ARRAY['ASIA-CAUCASUS'],ARRAY['partnership','integration','ties','cooperation','energy security','strategic partnership','grand deal','moral','justice','SOCAR','Southern Gas Corridor','Partnerschaft','Integration','Zusammenarbeit','moralisch','партнерство','сотрудничество'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','ANSA','La Repubblica','El País','Novinite','OilPrice','Carnegie Endowment','NPR','Daily Sabah','Anadolu Agency','TRT World','Jerusalem Post','The Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS'],'caucasus_power_competition',1,'Beneficial external partnership','Nützliche externe Partnerschaft',1,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cpc_russia_iran_resistance','Outside penetration of the region is a hostile encirclement to be resisted','Das Eindringen von außen in die Region ist eine feindliche Einkreisung, der zu widerstehen ist','A Russian and Iranian framing casts outside engagement as hostile penetration: US, Turkish and Israeli inroads -- bases, energy and arms deals, and transport corridors -- threaten Russian and Iranian interests and regional stability and are to be resisted through their own partnerships, amid frictions such as the disputes between Russia and Azerbaijan.','Eine russische und iranische Deutung stellt das äußere Engagement als feindliches Eindringen dar: US-amerikanische, türkische und israelische Vorstöße -- Stützpunkte, Energie- und Rüstungsgeschäfte sowie Transportkorridore -- bedrohten russische und iranische Interessen und die regionale Stabilität und seien durch eigene Partnerschaften abzuwehren, inmitten von Reibungen wie den Streitigkeiten zwischen Russland und Aserbaidschan.',ARRAY['ASIA-CAUCASUS'],ARRAY['encirclement','penetration','inroads','threat to stability','red line','foreign base','resist','sphere of influence','espionage','Einkreisung','Vordringen','rote Linie','Bedrohung','угроза','вторжение','красная линия','сфера влияния','шпионаж'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian','IRNA','Press TV'],'caucasus_power_competition',2,'Hostile encirclement / resistance','Feindliche Einkreisung / Widerstand', -2,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('caucasus_western_consensus','The South Caucasus is realigning westward -- peace, connectivity and a break from Russia','Der Südkaukasus richtet sich neu nach Westen aus -- Frieden, Konnektivität und ein Bruch mit Russland','Western, Turkish and Israeli coverage reads the South Caucasus as tilting decisively toward the West and a post-Russian order: Armenia''s European pivot, a US-brokered Armenia-Azerbaijan peace, opening trade corridors, and recognition of historic wrongs together mark a strategic realignment away from Moscow.','Die westliche, türkische und israelische Berichterstattung liest den Südkaukasus als klar nach Westen und zu einer nachrussischen Ordnung neigend: Armeniens europäischer Schwenk, ein von den USA vermittelter Frieden zwischen Armenien und Aserbaidschan, sich öffnende Handelskorridore und die Anerkennung historischen Unrechts markierten zusammen eine strategische Neuordnung weg von Moskau.',ARRAY['ASIA-CAUCASUS'],ARRAY['realignment','pivot','peace','connectivity','European','away from Russia','Neuordnung','Frieden','realignment'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Bloomberg','Washington Post','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Tagesschau','ANSA','La Repubblica','El País','Le Figaro','Carnegie Endowment','Novinite','Kyiv Post','LRT English','The Economist','The National','Daily Sabah','Anadolu Agency','TRT World','Jerusalem Post','The Jerusalem Post','Times of Israel','The Times of Israel','i24NEWS'],'caucasus_theater',1,'Western/regional realignment consensus','Konsens westlicher/regionaler Neuordnung',2,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('caucasus_russia_china_counter','The West is destabilizing Russia''s neighbourhood and dragging it into an anti-Russian orbit','Der Westen destabilisiert Russlands Nachbarschaft und zieht sie in eine antirussische Umlaufbahn','Russian and Chinese state media frame the same events as reckless Western expansionism: election interference, colour-revolution engineering and Turkish/US/Israeli penetration are destabilizing Russia''s traditional sphere and steering the Caucasus toward a "Ukraine scenario" of chaos and dependency.','Russische und chinesische Staatsmedien deuten dieselben Ereignisse als rücksichtslosen westlichen Expansionismus: Wahleinmischung, das Inszenieren von Farbrevolutionen und türkisch/US-amerikanisch/israelisches Vordringen destabilisierten Russlands traditionelle Sphäre und steuerten den Kaukasus in ein "Ukraine-Szenario" aus Chaos und Abhängigkeit.',ARRAY['ASIA-CAUCASUS'],ARRAY['interference','colour revolution','Ukraine scenario','encirclement','expansionism','destabiliz','Einmischung','Farbrevolution','вмешательство','дестабилизац'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian','CGTN','news.cgtn.com','Global Times','China Daily','People''s Daily','Xinhua'],'caucasus_theater',2,'Russia/China counter-narrative','Gegenerzählung Russlands/Chinas', -2,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ggd_european_aspiration','Georgians want a European future their government is betraying','Georgier wollen eine europäische Zukunft, die ihre Regierung verrät','Western framing backs Georgia''s pro-European majority against a Georgian Dream government sliding toward Moscow: a Russian-style foreign-agent law, EU-accession freeze, contested elections and street protests met with a crackdown mark a democratic backsliding away from the European path.','Die westliche Deutung stellt sich hinter Georgiens proeuropäische Mehrheit gegen eine Regierung des Georgischen Traums, die Richtung Moskau abdriftet: ein Agentengesetz nach russischem Vorbild, eingefrorener EU-Beitritt, umstrittene Wahlen und niedergeschlagene Straßenproteste markieren einen demokratischen Rückschritt weg vom europäischen Weg.',ARRAY['ASIA-CAUCASUS'],ARRAY['pro-European','pro-EU','protests','democracy','foreign agent','backsliding','crackdown','European path','candidate status','betray','proeuropäisch','Proteste','Rückschritt','Agentengesetz','проевропейск','протесты','иностранных агентов'],true,ARRAY['Reuters','Euronews','Euronews.com','France 24 (EN)','France 24','BBC World','Associated Press','The Guardian','CNN','Deutsche Welle','EurActiv','Financial Times','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Der Standard','Politico','Novinite','iROZHLAS'],'georgia_geopolitical_drift',1,'European aspiration betrayed','Verratene europäische Perspektive',2,true) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ggd_sovereignty_stability','Tbilisi is resisting a Western-orchestrated colour revolution and defending its sovereignty','Tiflis widersteht einer vom Westen orchestrierten Farbrevolution und verteidigt seine Souveränität','Russian state framing praises the Georgian government for resisting a Western-funded "colour revolution": the foreign-agent law is legitimate self-defense against NGO subversion, the protests are an externally engineered Maidan, and Tbilisi is defending sovereignty and stability against EU coercion.','Die russische Staatsdeutung lobt die georgische Regierung für den Widerstand gegen eine westlich finanzierte "Farbrevolution": das Agentengesetz sei legitime Selbstverteidigung gegen NGO-Unterwanderung, die Proteste ein von außen inszenierter Maidan, und Tiflis verteidige Souveränität und Stabilität gegen EU-Zwang.',ARRAY['ASIA-CAUCASUS'],ARRAY['colour revolution','color revolution','Maidan','sovereignty','stability','Western-funded','NGO','subversion','coercion','interference','Farbrevolution','Souveränität','Einmischung','цветная революция','майдан','суверенитет','вмешательство'],true,ARRAY['TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia','BelTA','BelTA Russian'],'georgia_geopolitical_drift',2,'Anti-Western sovereignty defense','Antiwestliche Souveränitätsverteidigung', -2,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('zc_connectivity_prosperity','The corridor unlocks connectivity, trade and a regional peace dividend','Der Korridor erschließt Konnektivität, Handel und eine regionale Friedensdividende','Western, Turkish and Azerbaijani framing presents the Zangezur route -- rebranded the US-backed "Trump Route"/TRIPP -- as a transformative connectivity project unlocking east-west trade, jobs and a peace dividend for the whole region.','Die westliche, türkische und aserbaidschanische Deutung präsentiert die Sangesur-Route -- neu benannt als US-gestützte "Trump-Route"/TRIPP -- als transformatives Konnektivitätsprojekt, das Ost-West-Handel, Arbeitsplätze und eine Friedensdividende für die ganze Region erschließt.',ARRAY['ASIA-CAUCASUS'],ARRAY['connectivity','trade route','prosperity','peace dividend','unlock','transit hub','east-west','Trump Route','TRIPP','Konnektivität','Handelsroute','Wohlstand','Trump-Route','коридор','торговый маршрут'],true,ARRAY['Reuters','Euronews','Euronews.com','Associated Press','Bloomberg','Financial Times','OilPrice','Daily Sabah','Anadolu Agency','TRT World','The Astana Times','Tengrinews','ANSA'],'zangezur_corridor',1,'Connectivity and prosperity','Konnektivität und Wohlstand',1,false) ;
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('zc_sovereignty_threat','The corridor is an extraterritorial threat to Armenian sovereignty and Iran''s border','Der Korridor ist eine extraterritoriale Bedrohung für Armeniens Souveränität und Irans Grenze','An Iranian and Russian framing warns the corridor is a strategic threat: an extraterritorial route carving through Armenian sovereign territory, severing Iran''s land border with Armenia and inserting US/NATO influence -- a red line to be blocked, not a peace project.','Eine iranische und russische Deutung warnt, der Korridor sei eine strategische Bedrohung: eine extraterritoriale Route mitten durch armenisches Hoheitsgebiet, die Irans Landgrenze zu Armenien durchtrenne und US-/NATO-Einfluss einschleuse -- eine rote Linie, die zu blockieren sei, kein Friedensprojekt.',ARRAY['ASIA-CAUCASUS'],ARRAY['extraterritorial','sovereignty','red line','sever','border','security risk','US influence','NATO','block','threat','extraterritorial','Souveränität','rote Linie','Grenze','экстерриториальн','суверенитет','красная линия','угроза'],true,ARRAY['IRNA','Press TV','TASS (EN)','TASS','tass.com','RT','RIA Novosti','Lenta.ru','Gazeta.ru','gazeta.ru','Kommersant','Izvestia'],'zangezur_corridor',2,'Sovereignty and red-line threat','Souveränitäts- und Grenzbedrohung', -1,false) ;
INSERT INTO strategic_assets (id,name_en,name_de,asset_type,geometry,commodities,centroid_ids,criticality,meta,description_en,description_de,is_active,subcategory) VALUES ('shah_deniz_field','Shah Deniz Field','Shah-Deniz-Feld','production_cluster','{"type": "Polygon", "coordinates": [[[50.1, 40.2], [50.7, 40.2], [50.7, 39.7], [50.1, 39.7], [50.1, 40.2]]]}',ARRAY['gas'],ARRAY['ASIA-CAUCASUS'],3,'{"aliases": ["Shah Deniz", "Shah Deniz Field"], "rank_note": "Azerbaijan''s flagship Caspian gas field feeding the Southern Gas Corridor to Europe.", "ranking_source": "EIA/IGU (Azerbaijan''s flagship Caspian gas field)"}','Azerbaijan''s largest gas field, whose output feeds the Southern Gas Corridor and has made the country a small but valued non-Russian supplier to Southeastern Europe.','Aserbaidschans groesstes Gasfeld, dessen Foerderung den Suedlichen Gaskorridor speist und das Land zu einem kleinen, aber geschaetzten nicht-russischen Lieferanten fuer Suedosteuropa gemacht hat.',true,'field') ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en,name_de=EXCLUDED.name_de,asset_type=EXCLUDED.asset_type,geometry=EXCLUDED.geometry,commodities=EXCLUDED.commodities,centroid_ids=EXCLUDED.centroid_ids,criticality=EXCLUDED.criticality,meta=EXCLUDED.meta,description_en=EXCLUDED.description_en,description_de=EXCLUDED.description_de,is_active=EXCLUDED.is_active,subcategory=EXCLUDED.subcategory;
INSERT INTO strategic_assets (id,name_en,name_de,asset_type,geometry,commodities,centroid_ids,criticality,meta,description_en,description_de,is_active,subcategory) VALUES ('scp_pipeline','South Caucasus Pipeline','Suedkaukasus-Pipeline','pipeline','{"type": "LineString", "coordinates": [[49.208, 40.163], [49.136, 40.104], [48.96, 40.07], [48.492, 40.269], [48.299, 40.287], [47.699, 40.489], [47.558, 40.471], [47.453, 40.517], [47.425, 40.577], [47.267, 40.62], [47.218, 40.591], [47.12, 40.633], [46.85, 40.658], [46.693, 40.637], [46.537, 40.821], [46.346, 40.862], [46.213, 40.843], [46.025, 40.899], [45.686, 41.07], [45.604, 41.079], [45.43, 41.254], [45.204, 41.365], [44.98, 41.565], [44.782, 41.467], [44.583, 41.455], [44.486, 41.477], [44.368, 41.586], [44.275, 41.622], [43.894, 41.604], [43.744, 41.671], [43.565, 41.619], [43.306, 41.701], [43.115, 41.659], [42.933, 41.601], [42.795, 41.51], [42.745, 41.237], [42.674, 41.209], [42.706, 41.103], [42.851, 40.957], [42.895, 40.836], [42.839, 40.741], [42.734, 40.601], [42.4, 40.43], [42.316, 40.35], [42.288, 40.264], [41.974, 40.003], [41.66, 39.932], [41.274, 39.966]]}',ARRAY['gas'],ARRAY['ASIA-CAUCASUS','MIDEAST-TURKEY'],3,'{"aliases": ["South Caucasus Pipeline", "SCP", "Baku-Tbilisi-Erzurum"], "rank_note": "Carries Shah Deniz gas from Azerbaijan via Georgia to Turkey -- the first leg of the Southern Gas Corridor to Europe, running parallel to the BTC oil line.", "route_source": "Global Energy Monitor GOIT/GGIT (shared BTC/SCP corridor to Erzurum)", "route_license": "CC BY 4.0", "ranking_source": "Global Energy Monitor GGIT route tracker"}','Carries Azerbaijani gas from the Shah Deniz field across Georgia to the Turkish border, forming the first leg of the Southern Gas Corridor that supplies non-Russian gas to Southeastern Europe, parallel to the Baku-Tbilisi-Ceyhan oil pipeline.','Transportiert aserbaidschanisches Gas vom Shah-Deniz-Feld ueber Georgien zur tuerkischen Grenze und bildet die erste Etappe des Suedlichen Gaskorridors, der Suedosteuropa mit nicht-russischem Gas versorgt, parallel zur Baku-Tiflis-Ceyhan-Oelpipeline.',true,'gas_pipeline') ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en,name_de=EXCLUDED.name_de,asset_type=EXCLUDED.asset_type,geometry=EXCLUDED.geometry,commodities=EXCLUDED.commodities,centroid_ids=EXCLUDED.centroid_ids,criticality=EXCLUDED.criticality,meta=EXCLUDED.meta,description_en=EXCLUDED.description_en,description_de=EXCLUDED.description_de,is_active=EXCLUDED.is_active,subcategory=EXCLUDED.subcategory;
INSERT INTO strategic_assets (id,name_en,name_de,asset_type,geometry,commodities,centroid_ids,criticality,meta,description_en,description_de,is_active,subcategory) VALUES ('sangachal_terminal','Sangachal Terminal','Sangachal-Terminal','port','{"type": "Point", "coordinates": [49.47, 40.17]}',ARRAY['oil','gas'],ARRAY['ASIA-CAUCASUS'],3,'{"aliases": ["Sangachal", "Sangachal Terminal"], "rank_note": "One of the world''s largest oil and gas terminals; the origin point of the BTC oil pipeline and the South Caucasus gas pipeline.", "ranking_source": "BP/AIOC operator disclosures; EIA Azerbaijan country analysis"}','A large oil and gas processing and export terminal on Azerbaijan''s Caspian coast south of Baku, where output from the offshore Azeri-Chirag-Gunashli oil fields and the Shah Deniz gas field is gathered before entering the BTC and South Caucasus pipelines.','Ein grosses Oel- und Gasaufbereitungs- und Exportterminal an Aserbaidschans Kaspikueste suedlich von Baku, wo die Foerderung der Offshore-Oelfelder Azeri-Chirag-Gunaschli und des Gasfelds Shah Deniz gesammelt wird, bevor sie in die BTC- und die Suedkaukasus-Pipeline eingespeist wird.',true,'energy') ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en,name_de=EXCLUDED.name_de,asset_type=EXCLUDED.asset_type,geometry=EXCLUDED.geometry,commodities=EXCLUDED.commodities,centroid_ids=EXCLUDED.centroid_ids,criticality=EXCLUDED.criticality,meta=EXCLUDED.meta,description_en=EXCLUDED.description_en,description_de=EXCLUDED.description_de,is_active=EXCLUDED.is_active,subcategory=EXCLUDED.subcategory;
